where
    Contract: cuda_core::KernelLaunchContract,
{
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("PreparedAsyncKernelLaunch")
            .field("contract", &Contract::SPEC.kernel_name())
            .finish_non_exhaustive()
    }
}

